```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Start a transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return 1; // Return error if transaction start fails
  }

  // Build and execute the delete statement with where condition
  using namespace sqlgen::literals;
  auto delete_stmt = sqlgen::delete_from<User> | where("last_login"_c < "2025-01-01");
  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    conn->rollback();
    return 1; // Return error if delete operation fails
  }

  // Commit the transaction
  auto commit_result = conn->commit();
  if (!commit_result) {
    conn->rollback();
    return 1; // Return error if commit fails
  }

  return 0; // Success
}

} // namespace delete_inactive_users
```

