namespace update_inventory_stock {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int stock;
};

bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }

  // Create the Product table if it doesn't exist
  auto create_result = create_table<Product>(conn_result.value());
  if (!create_result) {
    return false;
  }

  // Start a transaction
  auto transaction_result = begin_transaction(conn_result.value());
  if (!transaction_result) {
    return false;
  }

  // Iterate through the received products and update stock levels
  for (const auto& [product_id, quantity] : received) {
    // Build the UPDATE statement using sqlgen's type-safe query building
    auto update_stmt = update<Product>("stock"_c.set("stock"_c + quantity)) 
                     | where("product_id"_c == product_id);

    // Execute the update statement
    auto update_result = update_stmt(conn_result.value());
    if (!update_result) {
      // Rollback transaction on failure
      rollback(conn_result.value());
      return false;
    }
  }

  // Commit the transaction if all updates were successful
  auto commit_result = commit(conn_result.value());
  return commit_result;
}

}  // namespace update_inventory_stock
